internal final class Etg_RegisterPurchReportController extends SrsReportRunController
{
}

Method.Source:
public static Etg_RegisterPurchReportController construct()
{
    return new Etg_RegisterPurchReportController();
}

public static void main(Args _args)
{
    Etg_RegisterPurchReportController controller = Etg_RegisterPurchReportController::construct();

    controller.parmArgs(_args);
    if (ETGACFParameters::find().EnablePurchRegisterReportChanges == NoYes::Yes)
    {
        controller.parmReportName(ssrsReportStr(Etg_Register_PurchReport, Report));
    }
    else 
    {
        controller.parmReportName(ssrsReportStr(Etg_Register_PurchReport, RegisterPurchWithoutGRN));
    }
    controller.startOperation();
}
